INSERT INTO public.example_sentences (id, word_id, hebrew, translation_ru, transliteration, audio_url, level_id) VALUES (171, 97, 'החיילים שנלחמו בקרב חזרו הביתה', 'Солдаты, сражавшиеся в бою, вернулись домой', 'hа-хайялИм шэ-нилхамУ ба-крАв хазрУ hа-бАйта', NULL, 3);
