INSERT INTO public.example_sentences (id, word_id, hebrew, translation_ru, transliteration, audio_url, level_id) VALUES (178, 156, 'המתנדבים הצילו כלב שננטש ברחוב', 'Волонтёры спасли собаку, которую бросили на улице', 'hа-митнадвИм hицИлу кЭлев шэ-нинтАш ба-рехОв', NULL, 3);
