INSERT INTO public.example_sentences (id, word_id, hebrew, translation_ru, transliteration, audio_url, level_id) VALUES (211, 405, 'החברה השלימה את תהליך המיזוג בהצלחה', 'Компания успешно завершила процесс слияния', 'hа-хэврА hишлИма эт таhалИх hа-мизУг бэ-hацлахА', NULL, 4);
