INSERT INTO public.example_sentences (id, word_id, hebrew, translation_ru, transliteration, audio_url, level_id) VALUES (213, 729, 'מערכת החינוך מתמודדת עם אתגרי העידן הדיגיטלי', 'Система образования справляется с вызовами цифровой эпохи', 'маарЭхет hа-хинУх митмодЭдет им атгарЭй hа-идАн hа-дигитАли', NULL, 4);
INSERT INTO public.example_sentences (id, word_id, hebrew, translation_ru, transliteration, audio_url, level_id) VALUES (214, 729, 'כל אחד מתמודד עם קשיים בדרכו שלו', 'Каждый справляется с трудностями по-своему', 'коль эхАд митмодЭд им кшийИм бэ-даркО шелО', NULL, 4);
INSERT INTO public.example_sentences (id, word_id, hebrew, translation_ru, transliteration, audio_url, level_id) VALUES (215, 729, 'התמודדנו עם בעיות תקציביות מורכבות', 'Мы справились со сложными бюджетными проблемами', 'hитмодАдну им бэайОт такцивийОт муркавОт', NULL, 4);
INSERT INTO public.example_sentences (id, word_id, hebrew, translation_ru, transliteration, audio_url, level_id) VALUES (216, 944, 'החקיקה החדשה נועדה להגביל את כוחן של חברות הטכנולוגיה', 'Новое законодательство призвано ограничить власть технологических компаний', 'hа-хакикА hа-хадашА ноадА лэhагбИль эт кохАн шель хэврОт hа-технолОгия', NULL, 5);
INSERT INTO public.example_sentences (id, word_id, hebrew, translation_ru, transliteration, audio_url, level_id) VALUES (217, 944, 'אין להגביל את חופש הביטוי ללא הצדקה משפטית מוצקה', 'Нельзя ограничивать свободу слова без убедительного юридического обоснования', 'эйн лэhагбИль эт хОфеш hа-битУй лелО hацдакА мишпатИт муцЭкет', NULL, 5);
INSERT INTO public.example_sentences (id, word_id, hebrew, translation_ru, transliteration, audio_url, level_id) VALUES (218, 944, 'הסכם הסחר מגביל את היבוא של מוצרים מסוימים', 'Торговое соглашение ограничивает импорт определённых товаров', 'hэскЭм hа-сахАр магбИль эт hа-йевУ шель муцарИм месуямИм', NULL, 5);
INSERT INTO public.example_sentences (id, word_id, hebrew, translation_ru, transliteration, audio_url, level_id) VALUES (219, 944, 'המגבלות שהוטלו על התקשורת הגבילו את הדיווח העיתונאי', 'Ограничения, наложенные на СМИ, ограничили журналистскую деятельность', 'hа-магбалОт шэ-hутлУ аль hа-тикшОрет hигбИлу эт hа-дивУах hа-итонаИ', NULL, 5);
INSERT INTO public.example_sentences (id, word_id, hebrew, translation_ru, transliteration, audio_url, level_id) VALUES (220, 944, 'ממשלות רבות מבקשות להגביל את פליטת גזי החממה', 'Многие правительства стремятся ограничить выбросы парниковых газов', 'мемшалОт рабОт мевакшОт лэhагбИль эт плитАт газЭй hа-хамамА', NULL, 5);
INSERT INTO public.example_sentences (id, word_id, hebrew, translation_ru, transliteration, audio_url, level_id) VALUES (221, 945, 'תפקידו של בית המשפט העליון להגן על זכויות הפרט', 'Задача Верховного суда -- защищать права личности', 'тафкидО шель бэйт hа-мишпАт hа-эльйОн лэhагЭн аль зхуйОт hа-прАт', NULL, 5);
INSERT INTO public.example_sentences (id, word_id, hebrew, translation_ru, transliteration, audio_url, level_id) VALUES (222, 945, 'הארגון נלחם להגן על הסביבה מפני זיהום תעשייתי', 'Организация борется за защиту окружающей среды от промышленного загрязнения', 'hа-иргУн нилхАм лэhагЭн аль hа-свивА мипнЭй зиhУм таасийатИ', NULL, 5);
INSERT INTO public.example_sentences (id, word_id, hebrew, translation_ru, transliteration, audio_url, level_id) VALUES (223, 945, 'יש להגן על פרטיותם של אזרחים בעידן הדיגיטלי', 'Необходимо защищать частную жизнь граждан в цифровую эпоху', 'йеш лэhагЭн аль пратиютАм шель эзрахИм бэ-идАн hа-дигитАли', NULL, 5);
INSERT INTO public.example_sentences (id, word_id, hebrew, translation_ru, transliteration, audio_url, level_id) VALUES (224, 945, 'החוק מגן על עובדים מפני פיטורים שרירותיים', 'Закон защищает работников от произвольного увольнения', 'hа-хОк мэгЭн аль овдИм мипнЭй питурИм шрирутийИм', NULL, 5);
INSERT INTO public.example_sentences (id, word_id, hebrew, translation_ru, transliteration, audio_url, level_id) VALUES (225, 945, 'המדינה מחויבת להגן על אוכלוסייתה בעת חירום', 'Государство обязано защищать своё население в чрезвычайных ситуациях', 'hа-мединА мехуйЭвет лэhагЭн аль охлусийатА бэ-эт хирУм', NULL, 5);
INSERT INTO public.example_sentences (id, word_id, hebrew, translation_ru, transliteration, audio_url, level_id) VALUES (226, 947, 'החוקרים הציעו מודל תיאורטי חדש להסבר התופעה', 'Исследователи предложили новую теоретическую модель для объяснения явления', 'hа-хокрИм hицИу модЭль теоретИ хадАш лэ-hэсбЭр hа-тофаА', NULL, 5);
INSERT INTO public.example_sentences (id, word_id, hebrew, translation_ru, transliteration, audio_url, level_id) VALUES (227, 947, 'הוועדה הציעה רפורמה מקיפה במערכת הבריאות', 'Комиссия предложила комплексную реформу системы здравоохранения', 'hа-ваадА hицИа рефОрма макифА бэ-маарЭхет hа-бриУт', NULL, 5);
INSERT INTO public.example_sentences (id, word_id, hebrew, translation_ru, transliteration, audio_url, level_id) VALUES (228, 947, 'אני מציע לבחון את הנושא מנקודת מבט רב-תחומית', 'Я предлагаю рассмотреть вопрос с междисциплинарной точки зрения', 'ани мацИа ливхОн эт hа-носЭ мэ-некудАт мабАт рав-тхумИт', NULL, 5);
INSERT INTO public.example_sentences (id, word_id, hebrew, translation_ru, transliteration, audio_url, level_id) VALUES (229, 949, 'ישראל התחברה לרשת התקשורת הבינלאומית בשלב מוקדם', 'Израиль присоединился к международной сети связи на раннем этапе', 'исраЭль hитхабрА ла-рЭшет hа-тикшОрет hа-бэйнлеумИт бэ-шалАв мукдАм', NULL, 5);
INSERT INTO public.example_sentences (id, word_id, hebrew, translation_ru, transliteration, audio_url, level_id) VALUES (230, 949, 'הסטודנטים מתחברים לפלטפורמה האקדמית באמצעות סיסמה', 'Студенты подключаются к академической платформе с помощью пароля', 'hа-студЭнтим митхабрИм ла-плАтформа hа-акадЭмит бэ-эмцаУт сисмА', NULL, 5);
INSERT INTO public.example_sentences (id, word_id, hebrew, translation_ru, transliteration, audio_url, level_id) VALUES (231, 949, 'קשה להתחבר לטקסט שנכתב בשפה ארכאית', 'Сложно проникнуться текстом, написанным на архаичном языке', 'кашЭ лэhитхабЭр ла-тЭкст шэ-нихтАв бэ-сафА архАит', NULL, 5);
INSERT INTO public.example_sentences (id, word_id, hebrew, translation_ru, transliteration, audio_url, level_id) VALUES (232, 953, 'השכונה החדשה נבנית על שטח שהיה בעבר חקלאי', 'Новый район строится на территории, которая раньше была сельскохозяйственной', 'hа-шхунА hа-хадашА нивнЭт аль шЭтах шэ-hайА бэ-авАр хаклаИ', NULL, 5);
INSERT INTO public.example_sentences (id, word_id, hebrew, translation_ru, transliteration, audio_url, level_id) VALUES (295, 16, 'החלב בקירור', 'Молоко в холодильнике', 'hа-халАв ба-кирУр', NULL, 1);
INSERT INTO public.example_sentences (id, word_id, hebrew, translation_ru, transliteration, audio_url, level_id) VALUES (233, 953, 'האמון בין העמים נבנה לאורך שנים של שיתוף פעולה', 'Доверие между народами строилось на протяжении многих лет сотрудничества', 'hа-эмУн бэйн hа-амИм нивнА лэ-Орех шанИм шель шитУф пеулА', NULL, 5);
INSERT INTO public.example_sentences (id, word_id, hebrew, translation_ru, transliteration, audio_url, level_id) VALUES (234, 953, 'הטיעון נבנה על בסיס ראיות מוצקות', 'Аргументация строилась на основе убедительных доказательств', 'hа-тиУн нивнА аль басИс раайОт муцакОт', NULL, 5);
INSERT INTO public.example_sentences (id, word_id, hebrew, translation_ru, transliteration, audio_url, level_id) VALUES (235, 954, 'המחקר הזה נחשב לפריצת דרך בתחום הנוירולוגיה', 'Это исследование считается прорывом в области неврологии', 'hа-мэхкАр hа-зЭ нэхшАв ли-прицАт дЭрех бэ-тхУм hа-нейролОгия', NULL, 5);
INSERT INTO public.example_sentences (id, word_id, hebrew, translation_ru, transliteration, audio_url, level_id) VALUES (236, 954, 'עמנואל קאנט נחשב לאחד הפילוסופים המשפיעים ביותר', 'Иммануил Кант считается одним из самых влиятельных философов', 'иманУэль кант нэхшАв лэ-ахАд hа-филосОфим hа-машпиИм бэ-йотЭр', NULL, 5);
INSERT INTO public.example_sentences (id, word_id, hebrew, translation_ru, transliteration, audio_url, level_id) VALUES (237, 954, 'ההחלטה הזו עלולה להיחשב כתקדים משפטי', 'Это решение может считаться правовым прецедентом', 'hа-hахлатА hа-зу алулА лэhэхашЭв кэ-такдИм мишпатИ', NULL, 5);
INSERT INTO public.example_sentences (id, word_id, hebrew, translation_ru, transliteration, audio_url, level_id) VALUES (238, 1035, 'הספורטאי ניצח את יריבו בתחרות בינלאומית יוקרתית, למרות שנחשב לחלש מבין המתחרים', 'Спортсмен победил соперника в престижном международном соревновании, несмотря на то что считался слабейшим среди участников', 'hа-спортАй ницЭах эт яривО бэ-тахарУт бэйнлеумИт йократИт, ламрОт шэ-нэхшАв лэ-халАш мибЭйн hа-митхарИм', NULL, 6);
INSERT INTO public.example_sentences (id, word_id, hebrew, translation_ru, transliteration, audio_url, level_id) VALUES (239, 1035, 'לנצח אינו רק עניין של כוח — זוהי אמנות הדורשת אסטרטגיה, משמעת ומסירות', 'Побеждать -- это не только вопрос силы; это искусство, требующее стратегии, дисциплины и преданности', 'ленацЭах эйнО рак иньЯн шель кОах — зОhи оманУт hа-дорЭшет астратЭгия, масмаАт у-мсирУт', NULL, 6);
INSERT INTO public.example_sentences (id, word_id, hebrew, translation_ru, transliteration, audio_url, level_id) VALUES (240, 1035, '"מי שמנצח את יצרו — הוא הגיבור האמיתי", כתב בן זומא במשנה', '"Кто побеждает своё влечение -- тот истинный герой", написал Бен Зома в Мишне', '"ми шэ-менацЭах эт ицрО — hу hа-гибОр hа-амитИ", катАв бен зомА ба-мишнА', NULL, 6);
INSERT INTO public.example_sentences (id, word_id, hebrew, translation_ru, transliteration, audio_url, level_id) VALUES (241, 1035, 'צבא קטן ניצח צבא גדול ממנו פי כמה, בזכות תושייה וידע מקומי', 'Малая армия победила армию, в несколько раз превосходящую её, благодаря находчивости и знанию местности', 'цавА катАн ницЭах цавА гадОль мимЭну пи кАма, бэ-зхУт тушийА вэ-йЭда мекомИ', NULL, 6);
INSERT INTO public.example_sentences (id, word_id, hebrew, translation_ru, transliteration, audio_url, level_id) VALUES (242, 1035, 'האמת תמיד תנצח, גם אם דרכה ארוכה ומפותלת', 'Правда всегда победит, даже если её путь долог и извилист', 'hа-эмЭт тамИд тенацЭах, гам им даркА арукА у-мефуталЭт', NULL, 6);
INSERT INTO public.example_sentences (id, word_id, hebrew, translation_ru, transliteration, audio_url, level_id) VALUES (243, 1035, 'בגמר הטורניר, השחקנית ניצחה בשלושה סטים רצופים', 'В финале турнира шахматистка победила в трёх сетах подряд', 'бэ-гмАр hа-турнИр, hа-сахканИт ницхА бэ-шлошА сэтИм рецуфИм', NULL, 6);
INSERT INTO public.example_sentences (id, word_id, hebrew, translation_ru, transliteration, audio_url, level_id) VALUES (244, 1035, 'המפלגה ניצחה בבחירות בזכות תוכנית כלכלית שכנעה את מעמד הביניים', 'Партия победила на выборах благодаря экономической программе, убедившей средний класс', 'hа-мифлагА ницхА ба-бхирОт бэ-зхУт тохнИт калкалИт шэ-шихнА эт маамАд hа-бэйнАйим', NULL, 6);
INSERT INTO public.example_sentences (id, word_id, hebrew, translation_ru, transliteration, audio_url, level_id) VALUES (245, 1072, 'הגופים הביטחוניים הגבירו את הפעילות בעקבות האיום ההולך וגובר', 'Органы безопасности усилили деятельность в связи с нарастающей угрозой', 'hа-гуфИм hа-битхонийИм hигбИру эт hа-пеилУт бэ-иквОт hа-иЮм hа-hолЭх вэ-говЭр', NULL, 6);
INSERT INTO public.example_sentences (id, word_id, hebrew, translation_ru, transliteration, audio_url, level_id) VALUES (246, 1072, 'על התקשורת להגביר את המודעות הציבורית לסוגיות סביבתיות', 'СМИ должны усиливать общественную осведомлённость в экологических вопросах', 'аль hа-тикшОрет лэhагбИр эт hа-мудаУт hа-цибурИт лэ-сугийОт свиватийОт', NULL, 6);
INSERT INTO public.example_sentences (id, word_id, hebrew, translation_ru, transliteration, audio_url, level_id) VALUES (247, 1072, 'המשבר הפוליטי הגביר את חוסר האמון של הציבור במוסדות', 'Политический кризис усилил недоверие общества к институтам', 'hа-машбЭр hа-полИти hигбИр эт хОсер hа-эмУн шель hа-цибУр ба-мосадОт', NULL, 6);
INSERT INTO public.example_sentences (id, word_id, hebrew, translation_ru, transliteration, audio_url, level_id) VALUES (248, 1072, 'כדי להגביר את הביטחון, הותקנו מצלמות בכל רחבי העיר', 'Для усиления безопасности во всём городе были установлены камеры', 'кдЭй лэhагбИр эт hа-битахОн, hуткенУ мацлемОт бэ-холь рахавЭй hа-ир', NULL, 6);
INSERT INTO public.example_sentences (id, word_id, hebrew, translation_ru, transliteration, audio_url, level_id) VALUES (249, 1072, 'השימוש בבינה מלאכותית מגביר את היעילות אך מעלה שאלות אתיות מורכבות', 'Использование искусственного интеллекта усиливает эффективность, но поднимает сложные этические вопросы', 'hа-шимУш бэ-бинА малахутИт магбИр эт hа-йеилУт ах маалЭ шеэлОт этийОт муркавОт', NULL, 6);
INSERT INTO public.example_sentences (id, word_id, hebrew, translation_ru, transliteration, audio_url, level_id) VALUES (250, 1072, 'יש להגביר את המאמצים לצמצם פערים חברתיים-כלכליים', 'Необходимо усилить усилия по сокращению социально-экономических разрывов', 'йеш лэhагбИр эт hа-маамацИм лецамцЭм пеарИм хэвратийИм-калкалийИм', NULL, 6);
INSERT INTO public.example_sentences (id, word_id, hebrew, translation_ru, transliteration, audio_url, level_id) VALUES (251, 1186, 'בית הדין הרבני הוא הגוף היחיד המוסמך לאשר גירושין בישראל, מציאות שמעוררת ויכוח ציבורי נרחב', 'Раввинский суд является единственным органом, уполномоченным утверждать разводы в Израиле, что вызывает широкую общественную дискуссию', 'бэйт hа-дин hа-рабанИ hу hа-гуф hа-яхИд hа-мусмАх лэ-ашЭр гирушИн бэ-исраЭль, мециУт шэ-меорЭрет вику́ах цибурИ нирхАв', NULL, 6);
INSERT INTO public.example_sentences (id, word_id, hebrew, translation_ru, transliteration, audio_url, level_id) VALUES (296, 16, 'הילד שותה חלב חם', 'Ребёнок пьёт горячее молоко', 'hа-йЭлед шотЭ халАв хам', NULL, 1);
INSERT INTO public.example_sentences (id, word_id, hebrew, translation_ru, transliteration, audio_url, level_id) VALUES (252, 1186, 'הזוג התגרש לאחר עשרים שנות נישואין, אך שמר על יחסים תקינים למען ילדיהם', 'Пара развелась после двадцати лет брака, но сохранила нормальные отношения ради детей', 'hа-зуг hитгарЭш лэ-ахАр эсрИм шнОт нисуИн, ах шамАр аль яхасИм текинИм лемАан йалдэйhЭм', NULL, 6);
INSERT INTO public.example_sentences (id, word_id, hebrew, translation_ru, transliteration, audio_url, level_id) VALUES (253, 1186, 'סוגיית הנשים המסורבות גט — נשים שבעליהן מסרבים להתגרש — נותרה אחד האתגרים החמורים ביותר בחברה הישראלית', 'Проблема женщин, которым отказывают в разводе -- чьи мужья отказываются разводиться -- остаётся одной из серьёзнейших проблем израильского общества', 'сугийАт hа-нашИм hа-месуравОт гет — нашИм шэ-баалэйhЭн месарвИм лэhитгарЭш — нотрА эхАд hа-атгарИм hа-хамурИм бэ-йотЭр ба-хэврА hа-исраэлИт', NULL, 6);
INSERT INTO public.example_sentences (id, word_id, hebrew, translation_ru, transliteration, audio_url, level_id) VALUES (254, 1186, 'מחקר סוציולוגי מצא כי שיעורי ההתגרשות עולים ככל שהעצמאות הכלכלית של נשים גוברת', 'Социологическое исследование обнаружило, что уровень разводов растёт по мере усиления экономической независимости женщин', 'мэхкАр социолОги мацА ки шиурЭй hа-hитгаршУт олИм кекОль шэ-hа-ацмаУт hа-калкалИт шель нашИм говЭрет', NULL, 6);
INSERT INTO public.example_sentences (id, word_id, hebrew, translation_ru, transliteration, audio_url, level_id) VALUES (255, 1186, 'בשירתו של יהודה עמיחי, הגירושין מתוארים כ"רעידת אדמה שקטה שמחלקת את הבית לשניים"', 'В поэзии Йегуды Амихая развод описывается как "тихое землетрясение, разделяющее дом надвое"', 'бэ-ширатО шель йеhудА амихАй, hа-гирушИн метоарИм кэ-"реидАт адамА шкетА шэ-мехалЭкет эт hа-бАйит лэ-шнАйим"', NULL, 6);
