INSERT INTO public.example_sentences (id, word_id, hebrew, translation_ru, transliteration, audio_url, level_id) VALUES (1675, 1420, 'הילדים משחקים בגן הציבורי', 'Дети играют в общественном парке', 'ha-yeladim mesakhakim ba-gan ha-tziburi', NULL, 3);
INSERT INTO public.example_sentences (id, word_id, hebrew, translation_ru, transliteration, audio_url, level_id) VALUES (1676, 1460, 'אני לא יכול לבוא מחר בבוקר', 'Я не могу прийти завтра утром', 'ani lo yakhol lavo makhar ba-boker', NULL, 3);
INSERT INTO public.example_sentences (id, word_id, hebrew, translation_ru, transliteration, audio_url, level_id) VALUES (1677, 1500, 'הוא למד עברית שלוש שנים', 'Он учил иврит три года', 'hu lamad ivrit shalosh shanim', NULL, 3);
INSERT INTO public.example_sentences (id, word_id, hebrew, translation_ru, transliteration, audio_url, level_id) VALUES (1678, 1540, 'המסעדה הזאת פתוחה כל יום', 'Этот ресторан открыт каждый день', 'ha-mis''ada ha-zot ptukha kol yom', NULL, 3);
INSERT INTO public.example_sentences (id, word_id, hebrew, translation_ru, transliteration, audio_url, level_id) VALUES (1679, 1580, 'אנחנו גרים בדירה קטנה בתל אביב', 'Мы живём в маленькой квартире в Тель-Авиве', 'anakhnu garim be-dira ktana be-tel aviv', NULL, 3);
INSERT INTO public.example_sentences (id, word_id, hebrew, translation_ru, transliteration, audio_url, level_id) VALUES (1680, 1620, 'האוטובוס מגיע בעוד עשר דקות', 'Автобус приедет через десять минут', 'ha-otobus magia be-od eser dakot', NULL, 3);
INSERT INTO public.example_sentences (id, word_id, hebrew, translation_ru, transliteration, audio_url, level_id) VALUES (1681, 1660, 'היא קנתה שמלה חדשה לחתונה', 'Она купила новое платье на свадьбу', 'hi kanta simla khadasha la-khatuna', NULL, 3);
INSERT INTO public.example_sentences (id, word_id, hebrew, translation_ru, transliteration, audio_url, level_id) VALUES (1682, 1700, 'אנחנו צריכים לקנות ירקות ופירות', 'Нам нужно купить овощи и фрукты', 'anakhnu tzrikhim liknot yerakot u-perot', NULL, 3);
INSERT INTO public.example_sentences (id, word_id, hebrew, translation_ru, transliteration, audio_url, level_id) VALUES (1683, 1740, 'הרופא אמר שצריך לנוח יותר', 'Врач сказал, что нужно больше отдыхать', 'ha-rofe amar she-tzarikh lanuakh yoter', NULL, 3);
INSERT INTO public.example_sentences (id, word_id, hebrew, translation_ru, transliteration, audio_url, level_id) VALUES (1684, 1780, 'הסרט הזה מאוד מעניין ומרגש', 'Этот фильм очень интересный и волнующий', 'ha-seret ha-ze me''od me''anyen u-mergesh', NULL, 3);
INSERT INTO public.example_sentences (id, word_id, hebrew, translation_ru, transliteration, audio_url, level_id) VALUES (1685, 1820, 'היא מדברת שלוש שפות בשטף', 'Она бегло говорит на трёх языках', 'hi medaberet shalosh safot be-shetef', NULL, 3);
INSERT INTO public.example_sentences (id, word_id, hebrew, translation_ru, transliteration, audio_url, level_id) VALUES (1686, 1860, 'אנחנו נפגשים בכל שבוע ביום שלישי', 'Мы встречаемся каждую неделю во вторник', 'anakhnu nifgashim be-khol shavua be-yom shlishi', NULL, 3);
INSERT INTO public.example_sentences (id, word_id, hebrew, translation_ru, transliteration, audio_url, level_id) VALUES (1687, 1900, 'הוא עובד מהבית כבר שנה', 'Он работает из дома уже год', 'hu oved me-ha-bayit kvar shana', NULL, 3);
INSERT INTO public.example_sentences (id, word_id, hebrew, translation_ru, transliteration, audio_url, level_id) VALUES (1688, 1940, 'הבית שלנו נמצא ליד הים', 'Наш дом находится у моря', 'ha-bayit shelanu nimtza leyad ha-yam', NULL, 3);
INSERT INTO public.example_sentences (id, word_id, hebrew, translation_ru, transliteration, audio_url, level_id) VALUES (1689, 1980, 'הם חזרו מחופשה בחוץ לארץ', 'Они вернулись из отпуска за границей', 'hem khazru me-khufsha be-khutz la-aretz', NULL, 3);
INSERT INTO public.example_sentences (id, word_id, hebrew, translation_ru, transliteration, audio_url, level_id) VALUES (1690, 2020, 'את יכולה לעזור לי עם זה?', 'Ты можешь мне с этим помочь?', 'at yekhola la''azor li im ze?', NULL, 3);
INSERT INTO public.example_sentences (id, word_id, hebrew, translation_ru, transliteration, audio_url, level_id) VALUES (1691, 2060, 'הדודה שלי גרה בחיפה', 'Моя тётя живёт в Хайфе', 'ha-doda sheli gara be-kheifa', NULL, 3);
INSERT INTO public.example_sentences (id, word_id, hebrew, translation_ru, transliteration, audio_url, level_id) VALUES (1692, 2100, 'השמש שוקעת מוקדם בחורף', 'Солнце заходит рано зимой', 'ha-shemesh shoka''at mukdam ba-khoref', NULL, 3);
INSERT INTO public.example_sentences (id, word_id, hebrew, translation_ru, transliteration, audio_url, level_id) VALUES (1693, 2140, 'הם בנו בית חדש בכפר', 'Они построили новый дом в деревне', 'hem banu bayit khadash ba-kfar', NULL, 3);
INSERT INTO public.example_sentences (id, word_id, hebrew, translation_ru, transliteration, audio_url, level_id) VALUES (1694, 2180, 'המורה הסבירה את השיעור בבהירות', 'Учительница ясно объяснила урок', 'ha-mora hisbira et ha-shi''ur be-behirut', NULL, 3);
INSERT INTO public.example_sentences (id, word_id, hebrew, translation_ru, transliteration, audio_url, level_id) VALUES (1695, 2220, 'הוא רוצה לטייל בכל העולם', 'Он хочет путешествовать по всему миру', 'hu rotze letayel be-khol ha-olam', NULL, 3);
INSERT INTO public.example_sentences (id, word_id, hebrew, translation_ru, transliteration, audio_url, level_id) VALUES (1696, 2260, 'אנחנו אוכלים ארוחת ערב ביחד', 'Мы ужинаем вместе', 'anakhnu okhlim arukhat erev beyakhad', NULL, 3);
INSERT INTO public.example_sentences (id, word_id, hebrew, translation_ru, transliteration, audio_url, level_id) VALUES (1697, 2300, 'המשרד פתוח מתשע עד חמש', 'Офис открыт с девяти до пяти', 'ha-misrad patuakh me-tesha ad khamesh', NULL, 3);
INSERT INTO public.example_sentences (id, word_id, hebrew, translation_ru, transliteration, audio_url, level_id) VALUES (1698, 2340, 'היא שרה שיר יפה בהופעה', 'Она спела красивую песню на концерте', 'hi shara shir yafe ba-hofa''a', NULL, 3);
INSERT INTO public.example_sentences (id, word_id, hebrew, translation_ru, transliteration, audio_url, level_id) VALUES (1699, 2380, 'הגשם ירד כל היום אתמול', 'Дождь шёл весь день вчера', 'ha-geshem yarad kol ha-yom etmol', NULL, 3);
INSERT INTO public.example_sentences (id, word_id, hebrew, translation_ru, transliteration, audio_url, level_id) VALUES (1700, 2420, 'אנחנו מתכננים לנסוע לאילת', 'Мы планируем поехать в Эйлат', 'anakhnu metakhnanim linso''a le-eilat', NULL, 3);
INSERT INTO public.example_sentences (id, word_id, hebrew, translation_ru, transliteration, audio_url, level_id) VALUES (1701, 2460, 'הספרייה העירונית פתוחה גם בשבת', 'Городская библиотека открыта и в субботу', 'ha-sifriya ha-ironit ptukha gam be-shabat', NULL, 3);
INSERT INTO public.example_sentences (id, word_id, hebrew, translation_ru, transliteration, audio_url, level_id) VALUES (1702, 2500, 'הוא הזמין שולחן במסעדה לערב', 'Он заказал столик в ресторане на вечер', 'hu hizmin shulkhan ba-mis''ada la-erev', NULL, 3);
INSERT INTO public.example_sentences (id, word_id, hebrew, translation_ru, transliteration, audio_url, level_id) VALUES (1703, 2550, 'השכנים שלנו מאוד נחמדים', 'Наши соседи очень приятные', 'ha-shkhenim shelanu me''od nekhmadim', NULL, 3);
INSERT INTO public.example_sentences (id, word_id, hebrew, translation_ru, transliteration, audio_url, level_id) VALUES (1704, 2600, 'אני צריך ללכת לרופא שיניים', 'Мне нужно пойти к стоматологу', 'ani tzarikh lalekhet le-rofe shinayim', NULL, 3);
INSERT INTO public.example_sentences (id, word_id, hebrew, translation_ru, transliteration, audio_url, level_id) VALUES (1705, 2650, 'המחשב שלי לא עובד כמו שצריך', 'Мой компьютер не работает как надо', 'ha-makhshev sheli lo oved kmo she-tzarikh', NULL, 3);
INSERT INTO public.example_sentences (id, word_id, hebrew, translation_ru, transliteration, audio_url, level_id) VALUES (1706, 2700, 'היא סיימה את הלימודים בהצלחה', 'Она успешно закончила учёбу', 'hi siyma et ha-limudim be-hatzlakha', NULL, 3);
INSERT INTO public.example_sentences (id, word_id, hebrew, translation_ru, transliteration, audio_url, level_id) VALUES (1707, 2750, 'הילד הזה חכם מאוד לגילו', 'Этот ребёнок очень умный для своего возраста', 'ha-yeled ha-ze khakham me''od le-gilo', NULL, 3);
INSERT INTO public.example_sentences (id, word_id, hebrew, translation_ru, transliteration, audio_url, level_id) VALUES (1708, 2800, 'אנחנו צריכים לשלם את החשבון', 'Нам нужно оплатить счёт', 'anakhnu tzrikhim leshalem et ha-kheshbon', NULL, 3);
INSERT INTO public.example_sentences (id, word_id, hebrew, translation_ru, transliteration, audio_url, level_id) VALUES (1709, 2850, 'המוזיקה הישראלית מגוונת מאוד', 'Израильская музыка очень разнообразна', 'ha-muzika ha-yisraelit meguvenet me''od', NULL, 3);
INSERT INTO public.example_sentences (id, word_id, hebrew, translation_ru, transliteration, audio_url, level_id) VALUES (1710, 2900, 'הוא שיחק כדורגל כל ילדותו', 'Он играл в футбол всё детство', 'hu sikhek kaduregel kol yalduto', NULL, 3);
INSERT INTO public.example_sentences (id, word_id, hebrew, translation_ru, transliteration, audio_url, level_id) VALUES (1711, 2950, 'השוק בירושלים מלא צבעים וריחות', 'Рынок в Иерусалиме полон красок и запахов', 'ha-shuk bi-yerushalayim male tzva''im ve-reikhot', NULL, 3);
INSERT INTO public.example_sentences (id, word_id, hebrew, translation_ru, transliteration, audio_url, level_id) VALUES (1712, 3000, 'היא לומדת לתואר שני באוניברסיטה', 'Она учится на магистратуре в университете', 'hi lomedet le-to''ar sheni ba-universita', NULL, 3);
INSERT INTO public.example_sentences (id, word_id, hebrew, translation_ru, transliteration, audio_url, level_id) VALUES (1713, 3050, 'הם עברו לגור בשכונה חדשה', 'Они переехали жить в новый район', 'hem avru lagur bi-shkhuna khadasha', NULL, 3);
INSERT INTO public.example_sentences (id, word_id, hebrew, translation_ru, transliteration, audio_url, level_id) VALUES (1714, 3100, 'האוכל במסעדה הזאת מצוין', 'Еда в этом ресторане отличная', 'ha-okhel ba-mis''ada ha-zot metzuyan', NULL, 3);
INSERT INTO public.example_sentences (id, word_id, hebrew, translation_ru, transliteration, audio_url, level_id) VALUES (1715, 3150, 'אני שומע מוזיקה כשאני נוסע באוטו', 'Я слушаю музыку, когда еду в машине', 'ani shome''a muzika kshe-ani nose''a ba-oto', NULL, 3);
INSERT INTO public.example_sentences (id, word_id, hebrew, translation_ru, transliteration, audio_url, level_id) VALUES (1716, 3200, 'הוא קיבל מלגה ללימודים', 'Он получил стипендию на учёбу', 'hu kibel milga la-limudim', NULL, 3);
INSERT INTO public.example_sentences (id, word_id, hebrew, translation_ru, transliteration, audio_url, level_id) VALUES (1717, 3250, 'הפרחים בגינה פורחים באביב', 'Цветы в саду расцветают весной', 'ha-prakhim ba-gina porkhim ba-aviv', NULL, 3);
INSERT INTO public.example_sentences (id, word_id, hebrew, translation_ru, transliteration, audio_url, level_id) VALUES (1718, 3300, 'היא עשתה עוגה ליום ההולדת', 'Она испекла торт на день рождения', 'hi asta uga le-yom ha-huledet', NULL, 3);
INSERT INTO public.example_sentences (id, word_id, hebrew, translation_ru, transliteration, audio_url, level_id) VALUES (1719, 3350, 'אנחנו מטיילים בגליל כל קיץ', 'Мы путешествуем по Галилее каждое лето', 'anakhnu metaylim ba-galil kol kayitz', NULL, 3);
INSERT INTO public.example_sentences (id, word_id, hebrew, translation_ru, transliteration, audio_url, level_id) VALUES (1720, 3400, 'הבנק סגור ביום שישי אחר הצהריים', 'Банк закрыт в пятницу днём', 'ha-bank sagur be-yom shishi akhar ha-tzohorayim', NULL, 3);
INSERT INTO public.example_sentences (id, word_id, hebrew, translation_ru, transliteration, audio_url, level_id) VALUES (1721, 3450, 'הוא עזר לה לשאת את השקיות', 'Он помог ей нести сумки', 'hu azar la las''et et ha-sakiyot', NULL, 3);
INSERT INTO public.example_sentences (id, word_id, hebrew, translation_ru, transliteration, audio_url, level_id) VALUES (1722, 3500, 'המשפחה שלנו מתכנסת בחגים', 'Наша семья собирается по праздникам', 'ha-mishpakha shelanu mitkaneset ba-khagim', NULL, 3);
INSERT INTO public.example_sentences (id, word_id, hebrew, translation_ru, transliteration, audio_url, level_id) VALUES (1723, 3550, 'היא מכינה ארוחת בוקר כל יום', 'Она готовит завтрак каждый день', 'hi mekhina arukhat boker kol yom', NULL, 3);
INSERT INTO public.example_sentences (id, word_id, hebrew, translation_ru, transliteration, audio_url, level_id) VALUES (1724, 3600, 'הכביש הראשי סגור לתנועה', 'Главная дорога закрыта для движения', 'ha-kvish ha-rashi sagur li-tnu''a', NULL, 3);
INSERT INTO public.example_sentences (id, word_id, hebrew, translation_ru, transliteration, audio_url, level_id) VALUES (1725, 3650, 'אנחנו שמחים שבאתם לביקור', 'Мы рады, что вы пришли в гости', 'anakhnu smekhim she-batem le-bikur', NULL, 3);
INSERT INTO public.example_sentences (id, word_id, hebrew, translation_ru, transliteration, audio_url, level_id) VALUES (1726, 3700, 'הטלפון שלי צריך טעינה', 'Мой телефон нужно зарядить', 'ha-telefon sheli tzarikh te''ina', NULL, 3);
INSERT INTO public.example_sentences (id, word_id, hebrew, translation_ru, transliteration, audio_url, level_id) VALUES (1727, 3750, 'הוא נהג מונית עשרים שנה', 'Он водил такси двадцать лет', 'hu nahag monit esrim shana', NULL, 3);
INSERT INTO public.example_sentences (id, word_id, hebrew, translation_ru, transliteration, audio_url, level_id) VALUES (1728, 3800, 'המכתב הגיע בדואר היום', 'Письмо пришло по почте сегодня', 'ha-mikhtav higia ba-do''ar ha-yom', NULL, 3);
INSERT INTO public.example_sentences (id, word_id, hebrew, translation_ru, transliteration, audio_url, level_id) VALUES (1729, 3850, 'היא צילמה את הנוף מהמרפסת', 'Она сфотографировала вид с балкона', 'hi tzilma et ha-nof me-ha-mirpeset', NULL, 3);
INSERT INTO public.example_sentences (id, word_id, hebrew, translation_ru, transliteration, audio_url, level_id) VALUES (1730, 3900, 'השעון שלי מקדים בחמש דקות', 'Мои часы спешат на пять минут', 'ha-sha''on sheli makdim be-khamesh dakot', NULL, 3);
INSERT INTO public.example_sentences (id, word_id, hebrew, translation_ru, transliteration, audio_url, level_id) VALUES (1731, 3950, 'הם הזמינו אורחים לשבת', 'Они пригласили гостей на субботу', 'hem hizminu orkhim le-shabat', NULL, 3);
INSERT INTO public.example_sentences (id, word_id, hebrew, translation_ru, transliteration, audio_url, level_id) VALUES (1732, 4000, 'האופניים שלו נגנבו מהחניון', 'Его велосипед украли с парковки', 'ha-ofanayim shelo nignvu me-ha-khanyon', NULL, 3);
INSERT INTO public.example_sentences (id, word_id, hebrew, translation_ru, transliteration, audio_url, level_id) VALUES (1733, 4050, 'הילדה כתבה מכתב לסבתא', 'Девочка написала письмо бабушке', 'ha-yalda katva mikhtav la-savta', NULL, 3);
INSERT INTO public.example_sentences (id, word_id, hebrew, translation_ru, transliteration, audio_url, level_id) VALUES (1734, 1330, 'בבקשה תסגור את הדלת', 'Пожалуйста, закрой дверь', 'be-vakasha tisgor et ha-delet', NULL, 3);
INSERT INTO public.example_sentences (id, word_id, hebrew, translation_ru, transliteration, audio_url, level_id) VALUES (1735, 1370, 'מתי נפגשים מחר?', 'Когда встречаемся завтра?', 'matay nifgashim makhar?', NULL, 3);
INSERT INTO public.example_sentences (id, word_id, hebrew, translation_ru, transliteration, audio_url, level_id) VALUES (1736, 1410, 'אני מרגיש טוב היום', 'Я чувствую себя хорошо сегодня', 'ani margish tov ha-yom', NULL, 3);
INSERT INTO public.example_sentences (id, word_id, hebrew, translation_ru, transliteration, audio_url, level_id) VALUES (1737, 1450, 'הם הלכו לים בסוף השבוע', 'Они ходили на море в выходные', 'hem halkhu la-yam be-sof ha-shavua', NULL, 3);
INSERT INTO public.example_sentences (id, word_id, hebrew, translation_ru, transliteration, audio_url, level_id) VALUES (1738, 1490, 'הסיפור הזה נשמע מוזר', 'Эта история звучит странно', 'ha-sipur ha-ze nishma muzar', NULL, 3);
INSERT INTO public.example_sentences (id, word_id, hebrew, translation_ru, transliteration, audio_url, level_id) VALUES (1739, 1530, 'אנחנו חוגגים יום הולדת הערב', 'Мы празднуем день рождения сегодня вечером', 'anakhnu khogegim yom huledet ha-erev', NULL, 3);
INSERT INTO public.example_sentences (id, word_id, hebrew, translation_ru, transliteration, audio_url, level_id) VALUES (1740, 1570, 'הוא הבטיח לחזור מוקדם', 'Он обещал вернуться рано', 'hu hivtiakh lakhzor mukdam', NULL, 3);
INSERT INTO public.example_sentences (id, word_id, hebrew, translation_ru, transliteration, audio_url, level_id) VALUES (1741, 1610, 'התינוק ישן כל הלילה', 'Малыш спал всю ночь', 'ha-tinok yashan kol ha-layla', NULL, 3);
INSERT INTO public.example_sentences (id, word_id, hebrew, translation_ru, transliteration, audio_url, level_id) VALUES (1742, 1650, 'היא שכחה את הארנק בבית', 'Она забыла кошелёк дома', 'hi shakhkha et ha-arnak ba-bayit', NULL, 3);
INSERT INTO public.example_sentences (id, word_id, hebrew, translation_ru, transliteration, audio_url, level_id) VALUES (1743, 1690, 'הרכבת מאחרת בעשרים דקות', 'Поезд опаздывает на двадцать минут', 'ha-rakevet me''akheret be-esrim dakot', NULL, 3);
INSERT INTO public.example_sentences (id, word_id, hebrew, translation_ru, transliteration, audio_url, level_id) VALUES (1744, 1730, 'אנחנו גמרנו את כל האוכל', 'Мы съели всю еду', 'anakhnu gamarna et kol ha-okhel', NULL, 3);
INSERT INTO public.example_sentences (id, word_id, hebrew, translation_ru, transliteration, audio_url, level_id) VALUES (1745, 1770, 'הקפה פה מצוין', 'Кофе здесь отличный', 'ha-kafe po metzuyan', NULL, 3);
INSERT INTO public.example_sentences (id, word_id, hebrew, translation_ru, transliteration, audio_url, level_id) VALUES (1746, 1810, 'היא רצה מרתון בפעם הראשונה', 'Она пробежала марафон впервые', 'hi ratza maraton ba-pa''am ha-rishona', NULL, 3);
INSERT INTO public.example_sentences (id, word_id, hebrew, translation_ru, transliteration, audio_url, level_id) VALUES (1747, 1850, 'הם קנו דירה חדשה בראשון לציון', 'Они купили новую квартиру в Ришон-ле-Ционе', 'hem kanu dira khadasha be-rishon le-tziyon', NULL, 3);
INSERT INTO public.example_sentences (id, word_id, hebrew, translation_ru, transliteration, audio_url, level_id) VALUES (1748, 1890, 'אני לא אוהב לקום מוקדם', 'Я не люблю вставать рано', 'ani lo ohev lakum mukdam', NULL, 3);
INSERT INTO public.example_sentences (id, word_id, hebrew, translation_ru, transliteration, audio_url, level_id) VALUES (1749, 1930, 'הילד למד לרכוב על אופניים', 'Ребёнок научился ездить на велосипеде', 'ha-yeled lamad lirkov al ofanayim', NULL, 3);
INSERT INTO public.example_sentences (id, word_id, hebrew, translation_ru, transliteration, audio_url, level_id) VALUES (1750, 1970, 'חם מאוד בקיץ בישראל', 'Летом в Израиле очень жарко', 'kham me''od ba-kayitz be-yisrael', NULL, 3);
INSERT INTO public.example_sentences (id, word_id, hebrew, translation_ru, transliteration, audio_url, level_id) VALUES (1751, 2010, 'הסופרמרקט פתוח עד מאוחר', 'Супермаркет открыт допоздна', 'ha-supermarket patuakh ad me''ukhar', NULL, 3);
INSERT INTO public.example_sentences (id, word_id, hebrew, translation_ru, transliteration, audio_url, level_id) VALUES (1752, 1450, 'הממשלה אישרה את התקציב החדש', 'Правительство утвердило новый бюджет', 'ha-memshala ishra et ha-taktziv he-khadash', NULL, 4);
INSERT INTO public.example_sentences (id, word_id, hebrew, translation_ru, transliteration, audio_url, level_id) VALUES (1753, 1520, 'המשפט התנהל בבית המשפט המחוזי', 'Суд проходил в окружном суде', 'ha-mishpat hitnahel be-beit ha-mishpat ha-mekhozi', NULL, 4);
INSERT INTO public.example_sentences (id, word_id, hebrew, translation_ru, transliteration, audio_url, level_id) VALUES (1754, 1590, 'הכתבה חשפה שחיתות בממשלה', 'Репортаж раскрыл коррупцию в правительстве', 'ha-katava khasfa shkhitut ba-memshala', NULL, 4);
INSERT INTO public.example_sentences (id, word_id, hebrew, translation_ru, transliteration, audio_url, level_id) VALUES (1755, 1660, 'הפסיכולוג ניתח את התנהגות המטופל', 'Психолог проанализировал поведение пациента', 'ha-psikholog nitakh et hitnagut ha-metupal', NULL, 4);
INSERT INTO public.example_sentences (id, word_id, hebrew, translation_ru, transliteration, audio_url, level_id) VALUES (1756, 1730, 'הביוגרפיה מתארת את חייו של המנהיג', 'Биография описывает жизнь лидера', 'ha-biographia meta''eret et khayav shel ha-manhig', NULL, 4);
INSERT INTO public.example_sentences (id, word_id, hebrew, translation_ru, transliteration, audio_url, level_id) VALUES (1757, 1800, 'הרפורמה החינוכית יצרה מחלוקת', 'Образовательная реформа вызвала разногласия', 'ha-reforma ha-khinukhit yatzra makhloket', NULL, 4);
INSERT INTO public.example_sentences (id, word_id, hebrew, translation_ru, transliteration, audio_url, level_id) VALUES (1758, 1870, 'הבנק המרכזי פרסם דוח שנתי', 'Центральный банк опубликовал годовой отчёт', 'ha-bank ha-merkazi pirsem do''akh shnati', NULL, 4);
INSERT INTO public.example_sentences (id, word_id, hebrew, translation_ru, transliteration, audio_url, level_id) VALUES (1759, 1940, 'הצבא ביצע תרגיל בצפון הארץ', 'Армия провела учения на севере страны', 'ha-tzava bitze''a targil bi-tzfon ha-aretz', NULL, 4);
INSERT INTO public.example_sentences (id, word_id, hebrew, translation_ru, transliteration, audio_url, level_id) VALUES (1760, 2010, 'המחקר הוכיח קשר בין עישון לסרטן', 'Исследование доказало связь между курением и раком', 'ha-mekhkar hokhiakh kesher bein ishun le-sartan', NULL, 4);
INSERT INTO public.example_sentences (id, word_id, hebrew, translation_ru, transliteration, audio_url, level_id) VALUES (2056, 234, 'איפה היריד?', 'Где ярмарка?', NULL, NULL, 2);
INSERT INTO public.example_sentences (id, word_id, hebrew, translation_ru, transliteration, audio_url, level_id) VALUES (1761, 2080, 'הניסוי הצליח מעבר לציפיות', 'Эксперимент удался сверх ожиданий', 'ha-nisayon hitzsliakh me''ever la-tzipiyot', NULL, 4);
INSERT INTO public.example_sentences (id, word_id, hebrew, translation_ru, transliteration, audio_url, level_id) VALUES (1762, 2150, 'ההסכם נחתם בטקס רשמי', 'Соглашение подписано на официальной церемонии', 'ha-heskem nekhtam be-tekes rishmi', NULL, 4);
INSERT INTO public.example_sentences (id, word_id, hebrew, translation_ru, transliteration, audio_url, level_id) VALUES (1763, 2220, 'השוק הנדל"ני חווה עלייה חדה', 'Рынок недвижимости пережил резкий рост', 'ha-shuk ha-nadlani khava aliya khada', NULL, 4);
INSERT INTO public.example_sentences (id, word_id, hebrew, translation_ru, transliteration, audio_url, level_id) VALUES (1764, 2290, 'הדילמה המוסרית העסיקה את הציבור', 'Моральная дилемма занимала общество', 'ha-dilema ha-musarit he''esika et ha-tzibur', NULL, 4);
INSERT INTO public.example_sentences (id, word_id, hebrew, translation_ru, transliteration, audio_url, level_id) VALUES (1765, 2360, 'התקשורת סיקרה את האירוע בהרחבה', 'СМИ широко осветили событие', 'ha-tikshoret sikra et ha-iru''a be-harkhava', NULL, 4);
INSERT INTO public.example_sentences (id, word_id, hebrew, translation_ru, transliteration, audio_url, level_id) VALUES (1766, 2430, 'הנציגות הדיפלומטית התערבה בסכסוך', 'Дипломатическое представительство вмешалось в конфликт', 'ha-natzigut ha-diplomatit hit''arva ba-sikhsukh', NULL, 4);
INSERT INTO public.example_sentences (id, word_id, hebrew, translation_ru, transliteration, audio_url, level_id) VALUES (1767, 2500, 'הפרויקט הושלם במסגרת התקציב', 'Проект завершён в рамках бюджета', 'ha-proyekt hushlam be-misgeret ha-taktziv', NULL, 4);
INSERT INTO public.example_sentences (id, word_id, hebrew, translation_ru, transliteration, audio_url, level_id) VALUES (1768, 2570, 'החוקר פרסם מאמר בכתב עת בינלאומי', 'Учёный опубликовал статью в международном журнале', 'ha-khoker pirsem ma''amar be-ktav et bein-leumi', NULL, 4);
INSERT INTO public.example_sentences (id, word_id, hebrew, translation_ru, transliteration, audio_url, level_id) VALUES (1769, 2640, 'הוועדה המליצה על שינויים בחוק', 'Комиссия рекомендовала изменения в законе', 'ha-va''ada himlitza al shinuyim ba-khok', NULL, 4);
INSERT INTO public.example_sentences (id, word_id, hebrew, translation_ru, transliteration, audio_url, level_id) VALUES (1770, 2710, 'האוניברסיטה הציעה תכנית לימודים חדשה', 'Университет предложил новую учебную программу', 'ha-universita hetzi''a tokhnit limudim khadasha', NULL, 4);
INSERT INTO public.example_sentences (id, word_id, hebrew, translation_ru, transliteration, audio_url, level_id) VALUES (1771, 2780, 'ההפגנה התקיימה מול בניין העירייה', 'Демонстрация прошла перед зданием муниципалитета', 'ha-hafgana hitkayma mul binyan ha-iriya', NULL, 4);
INSERT INTO public.example_sentences (id, word_id, hebrew, translation_ru, transliteration, audio_url, level_id) VALUES (1772, 2850, 'הכלכלן חזה האטה בצמיחה', 'Экономист предсказал замедление роста', 'ha-kalkalan khaza ha''ata ba-tzmiha', NULL, 4);
INSERT INTO public.example_sentences (id, word_id, hebrew, translation_ru, transliteration, audio_url, level_id) VALUES (1773, 2920, 'הרפורמה הבריאותית עוררה ויכוח ער', 'Реформа здравоохранения вызвала оживлённый спор', 'ha-reforma ha-bri''utit orera vikuakh er', NULL, 4);
INSERT INTO public.example_sentences (id, word_id, hebrew, translation_ru, transliteration, audio_url, level_id) VALUES (1774, 2990, 'הסופר קיבל פרס ספרותי יוקרתי', 'Писатель получил престижную литературную премию', 'ha-sofer kibel pras sifruti yokrati', NULL, 4);
INSERT INTO public.example_sentences (id, word_id, hebrew, translation_ru, transliteration, audio_url, level_id) VALUES (1775, 3060, 'ההשקעה בחינוך מחזירה את עצמה', 'Инвестиции в образование окупаются', 'ha-hashka''a be-khinukh makhzira et atzma', NULL, 4);
INSERT INTO public.example_sentences (id, word_id, hebrew, translation_ru, transliteration, audio_url, level_id) VALUES (1776, 3130, 'הטכנולוגיה שינתה את שוק העבודה', 'Технология изменила рынок труда', 'ha-tekhnologia shinta et shuk ha-avoda', NULL, 4);
INSERT INTO public.example_sentences (id, word_id, hebrew, translation_ru, transliteration, audio_url, level_id) VALUES (1777, 3200, 'המשרד הוציא הנחיות חדשות', 'Министерство выпустило новые директивы', 'ha-misrad hotzi hanhayot khadashot', NULL, 4);
