INSERT INTO public.example_sentences (id, word_id, hebrew, translation_ru, transliteration, audio_url, level_id) VALUES (1793, 4320, 'החברה הודיעה על פיטורים המוניים', 'Компания объявила о массовых увольнениях', 'ha-khevra hodi''a al piturim hamoni''im', NULL, 4);
