INSERT INTO public.example_sentences (id, word_id, hebrew, translation_ru, transliteration, audio_url, level_id) VALUES (1819, 3240, 'הנציב פרסם דוח ביקורת', 'Контролёр опубликовал отчёт ревизии', 'ha-natziv pirsem do''akh bikoret', NULL, 4);
INSERT INTO public.example_sentences (id, word_id, hebrew, translation_ru, transliteration, audio_url, level_id) VALUES (1820, 3310, 'הפרלמנט אישר את החוק ברוב קולות', 'Парламент утвердил закон большинством голосов', 'ha-parlament isher et ha-khok be-rov kolot', NULL, 4);
