INSERT INTO public.example_sentences (id, word_id, hebrew, translation_ru, transliteration, audio_url, level_id) VALUES (1831, 5090, 'הסכסוך נפתר בדרכי שלום', 'Конфликт решён мирным путём', 'ha-sikhsukh niftar be-darkhei shalom', NULL, 4);
