INSERT INTO public.example_sentences (id, word_id, hebrew, translation_ru, transliteration, audio_url, level_id) VALUES (1947, 6350, 'הנורמטיביות קובעת מה נחשב לנכון ולראוי', 'Нормативность определяет, что считается правильным и должным', 'ha-normativiyut kova''at ma nekhshav le-nakhon u-le-ra''uy', NULL, 6);
